mapper.select:
SELECT TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TDS.SCN, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) else TRUST_SHIP."shipvoyageLabel" END shipvoyageLabel, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM STATUS_LABEL, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWT.CREATE_BY_NAME, TPWT.CREATE_TIME, TPWT.UPDATE_TIME, TPWT.UPDATE_BY_NAME, T8.CARGO_OWNER_NAME, T8.CARGO_OWNER_ID, T8.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T8.CARGO_INFO_NO, T5.TRUST_NO, T2.NUM AS LABOR_NUM, CASE WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) like '%1%' THEN '已签票' ELSE '待签票' END IS_SIGNED,
CASE WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) like '%2%' THEN '已签票' ELSE '待签票' END IS_SIGNED_KC FROM T_PRD_WORK_PLAN TPWP LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TPWP.SHIPVOYAGE_ID = TDS. ID LEFT JOIN M_SHIP MS ON TDS.SHIP_ID = MS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TPWP.SHIPVOYAGE_ITEM_ID = TDSI. ID JOIN M_CONSTANTS MC ON TPWP.STATUS = MC.CD AND MC.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN T_PRD_WORK_TICKET TPWT ON TPWP. ID = TPWT.WORK_PLAN_ID LEFT JOIN T_BUS_TRUST T5 ON TPWP.TRUST_ID = T5. ID LEFT JOIN ( SELECT A .TRUST_ID, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_INFO_NO), ',') WITHIN GROUP (ORDER BY T6.CARGO_INFO_NO) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_INFO_NO, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_NAME), ',') WITHIN GROUP (ORDER BY T6.CARGO_NAME) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_NAME, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_CODE), ',') WITHIN GROUP (ORDER BY T6.CARGO_CODE) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_CODE, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_OWNER_NAME), ',') WITHIN GROUP (ORDER BY T6.CARGO_OWNER_NAME) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_OWNER_NAME, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_OWNER_ID), ',') WITHIN GROUP (ORDER BY T6.CARGO_OWNER_ID) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_OWNER_ID, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_AGENT_NAME), ',') WITHIN GROUP (ORDER BY T6.CARGO_AGENT_NAME) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_AGENT_NAME, regexp_replace( LISTAGG (TO_CHAR(T6.PACKING_CODE), ',') WITHIN GROUP (ORDER BY T6.PACKING_CODE) , '([^,]+)(,\1)*(,|$)', '\1\3' ) PACKING_CODE FROM T_BUS_CARGO_INFO T6, T_BUS_TRUST_CARGO A, T_BUS_TRUST T5 WHERE A .CARGO_INFO_ID = T6. ID AND T5. ID = A .TRUST_ID GROUP BY A .TRUST_ID ) T8 ON T8.TRUST_ID = TPWP.TRUST_ID LEFT JOIN T_PRD_DISPATCH T2 ON TPWP. ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' left join (select TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCS.SHIP_NAME||'_'||TBCS.VOYAGE), ',') WITHIN GROUP ( ORDER BY TBCS.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) "shipvoyageLabel" ,TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TBCS.SHIP_VOYAGE_ITEM_ID), ',') WITHIN GROUP ( ORDER BY TBCS.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) SHIP_VOYAGE_ITEM_ID, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TDS.SCN), ',') WITHIN GROUP ( ORDER BY TBCS.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) SCN, TO_CHAR(REGEXP_REPLACE(LISTAGG(to_char(TDS.LOAD_UNLOAD), ',') WITHIN GROUP ( ORDER BY TBCS.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) LOAD_UNLOAD, TBCS.TRUST_ID from T_BUS_CARGO_SHIP TBCS left join T_DIS_SHIPVOYAGE TDS on TBCS.SHIP_VOYAGE_ID = TDS.ID group by TRUST_ID) TRUST_SHIP on TRUST_SHIP.TRUST_ID = TPWP.TRUST_ID WHERE TPWP.STATUS != 10
and (TPWP.FRONT_TALLY_BY like #{loginIdLike} OR TPWP.BACK_TALLY_BY like #{loginIdLike} OR TPWP.DISPATCH_BY like #{loginIdLike})
AND TPWP.WORK_DATE = #{workDate}
AND TPWP.CLASS_CODE = #{classCode}
AND T5.TRUST_NO = #{trustNo}
AND TPWP.PLAN_TYPE = #{planType}
AND case when TPWP.SHIPVOYAGE_ITEM_ID is null then to_char(TRUST_SHIP.SHIP_VOYAGE_ITEM_ID) else to_char(TPWP.SHIPVOYAGE_ITEM_ID) end = #{shipitemIdLike}
AND T8.CARGO_OWNER_ID like #{cargoOwnerIdLike}
AND T8.CARGO_CODE like #{cargoCodeLike}
AND T5.PORT_CODE = #{portCode}
AND T8.PACKING_CODE like #{packageCodeLike}
GROUP BY TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TDS.SCN, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) else TRUST_SHIP."shipvoyageLabel" END, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T8.CARGO_OWNER_NAME, T8.CARGO_OWNER_ID, T8.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T8.CARGO_INFO_NO, T5.TRUST_NO, TPWT.CREATE_BY_NAME, TPWT.CREATE_TIME, TPWT.UPDATE_TIME, TPWT.UPDATE_BY_NAME, T2.NUM ORDER By T5.TRUST_NO

SELECT TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END shipvoyageLabel, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM STATUS_LABEL, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T6.CARGO_OWNER_NAME, T6.CARGO_OWNER_ID, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T5.TRUST_NO, T5.TYPE, T2.NUM AS LABOR_NUM, CASE WHEN TPWT.ID IS NULL THEN '待审核' ELSE TO_CHAR( TPWT.WORK_TICKET_STATUS_NAME ) END WORK_TICKET_STATUS_NAME, CASE WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) IS NULL THEN '待签票' WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) = '1' THEN '调度已签票' WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) = '2' THEN '库场已签票' ELSE '调度/库场已签票' END IS_SIGNED
FROM T_PRD_WORK_PLAN TPWP LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TPWP.SHIPVOYAGE_ID = TDS. ID LEFT JOIN M_SHIP MS ON TDS.SHIP_ID = MS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TPWP.SHIPVOYAGE_ITEM_ID = TDSI. ID JOIN M_CONSTANTS MC ON TPWP.STATUS = MC.CD AND MC.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN T_PRD_WORK_TICKET TPWT ON TPWP. ID = TPWT.WORK_PLAN_ID LEFT JOIN T_BUS_TRUST T5 ON TPWP.TRUST_ID = T5. ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_OWNER_NAME), ',' ) WITHIN GROUP (ORDER BY CARGO_OWNER_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME, TRUST_ID, REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_OWNER_ID), ',' ) WITHIN GROUP (ORDER BY CARGO_OWNER_ID), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T6 ON T5. ID = T6.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG (TO_CHAR(CARGO_NAME), ',') WITHIN GROUP (ORDER BY CARGO_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_NAME, REGEXP_REPLACE ( LISTAGG (TO_CHAR(CARGO_CODE), ',') WITHIN GROUP (ORDER BY CARGO_CODE), '([^,]+)(,\1)+', '\1' ) CARGO_CODE, TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T8 ON T5. ID = T8.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_AGENT_NAME), ',' ) WITHIN GROUP (ORDER BY CARGO_AGENT_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME, TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T7 ON T5. ID = T7.TRUST_ID LEFT JOIN T_PRD_DISPATCH T2 ON TPWP. ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' WHERE TPWP.STATUS != 10
AND TPWP.WORK_DATE = #{workDate}
AND TPWP.CLASS_CODE = #{classCode}
AND TPWP.PLAN_TYPE = #{planType}
AND T5.TRUST_NO = #{trustNo}
AND T5.PORT_CODE = #{portCode}
GROUP BY TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T6.CARGO_OWNER_NAME, T6.CARGO_OWNER_ID, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T5.TRUST_NO, T5.TYPE, T2.NUM, CASE WHEN TPWT.ID IS NULL THEN '待审核' ELSE TO_CHAR( TPWT.WORK_TICKET_STATUS_NAME ) END ORDER BY PLAN_NO

SELECT TBCI.ID,
TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME, TBTC.TRUST_ID, TBTC.ID TRUST_CARGO_ID,
TBCI.CARGO_NAME || '/' || TBCI.CARGO_OWNER_NAME || '/' || TBCI.CARGO_INFO_NO CARGO_LABEL, TBT.PROCESS_CODE, TBT.PROCESS_NAME FROM T_PRD_WORK_PLAN TPWPT JOIN T_BUS_TRUST TBT ON TPWPT.TRUST_ID = TBT.ID JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID WHERE TPWPT.id = #{workPlanId, jdbcType=BIGINT}

SELECT TBCI.ID, TPWPT.ID WORK_PLAN_ID, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME, TBTC.TRUST_ID, TBTC.ID TRUST_CARGO_ID,
TBCI.CARGO_NAME || '/' || TBCI.CARGO_OWNER_NAME || '/' || TBCI.CARGO_INFO_NO CARGO_LABEL, TBT.PROCESS_CODE, TBT.PROCESS_NAME FROM T_PRD_WORK_PLAN TPWPT JOIN T_BUS_TRUST TBT ON TPWPT.TRUST_ID = TBT.ID JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID WHERE TPWPT.id IN
#{item}

SELECT
ID,
COMPANY_ID,
COMPANY_NAME,
DEPT_ID,
DEPT_NAME,
PIECE_PROJECT_CODE,
PIECE_PROJECT_NAME,
IS_UPDATE_STORAGE,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM M_PIECE_WORK_TEAM


        ID = #{id, jdbcType=BIGINT}


        AND COMPANY_ID = #{companyId, jdbcType=BIGINT}


        AND COMPANY_NAME = #{companyName, jdbcType=VARCHAR}


        AND DEPT_ID = #{deptId, jdbcType=BIGINT}


        AND DEPT_NAME = #{deptName, jdbcType=VARCHAR}


        AND PIECE_PROJECT_CODE = #{pieceProjectCode, jdbcType=VARCHAR}


        AND PIECE_PROJECT_NAME = #{pieceProjectName, jdbcType=VARCHAR}


        AND IS_UPDATE_STORAGE = #{isUpdateStorage, jdbcType=VARCHAR}


        AND CREATE_BY = #{createBy, jdbcType=BIGINT}


        AND CREATE_BY_NAME = #{createByName, jdbcType=VARCHAR}


        AND CREATE_TIME = #{createTime, jdbcType=TIMESTAMP}


        AND UPDATE_BY = #{updateBy, jdbcType=BIGINT}


        AND UPDATE_BY_NAME = #{updateByName, jdbcType=VARCHAR}


        AND UPDATE_TIME = #{updateTime, jdbcType=TIMESTAMP}


ORDER BY
    DEPT_NAME

SELECT ID, COMPANY_ID, COMPANY_NAME, WORK_PLAN_ID, TYPE, WORK_TICKET_STATUS, WORK_TICKET_STATUS_NAME, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, EXAMINE_BY, EXAMINE_BY_NAME, EXAMINE_TIME, WORK_DATE, CLASS_CODE, CLASS_NAME, PROCESS_CODE, PROCESS_NAME, DEPT_ID, DEPT_NAME, QUANTITY, TON FROM T_PRD_WORK_TICKET WHERE (is_old = '1' or is_old is null) and WORK_PLAN_ID = #{workPlanId, jdbcType=BIGINT}
AND TICKET_TYPE = #{ticketType,jdbcType=VARCHAR}
AND WORK_TICKET_STATUS = 20

