DELETE FROM T_PRD_SALARY
WHERE WORK_TICKET_DETAIL_ID IN

    #{workTicketDetailId}

mapper.select:
SELECT * from T_PRD_WORK_TICKET


        WORK_PLAN_ID = #{workPlanId}


        and TICKET_TYPE = #{ticketType}

SELECT
     SUM (A1.QUANTITY) "quantity",
     SUM (A1.TON) "ton"
 FROM
     T_YARD_TALLY_ITEM A1
 LEFT JOIN T_YARD_TALLY A2 ON A2. ID = A1.TALLY_ID
 WHERE
     A2.PLAN_ID =#{workPlanId,jdbcType=BIGINT}
 AND A1.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}
 AND A2.PROCESS_CODE = #{processDetailCode,jdbcType=VARCHAR}

SELECT T1.ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END SHIP_NAME_VOYAGE, T4.CARGO_OWNER_NAME || '/' || T4.CARGO_NAME || '/' || T4.CARGO_INFO_NO CARGO_NAME_LABEL, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID DEPT_ITEM_ID, T2.DEPT_NAME DEPT_ITEM_NAME, T2.CABIN_NO, T5.EQUIPMENT_TYPE_NAME, LISTAGG (T5.EQUIPMENT_NO, ',') WITHIN GROUP (ORDER BY T5.EQUIPMENT_NO) EQUIPMENT_NO, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END STOREHOUSE_NAME_SOURCE_LABEL, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END STOREHOUSE_NAME_TARGET_LABEL, T2.TON, T2.QUANTITY, TO_CHAR(T2.END_TIME,'yyyy-mm-dd hh24:mi') END_TIME, TO_CHAR ( T2.START_TIME, 'yyyy-mm-dd hh24:mi' ) START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO FROM T_PRD_WORK_TICKET T1 LEFT JOIN T_PRD_WORK_TICKET_DETAIL T2 ON T1. ID = T2.WORK_TICKET_ID LEFT JOIN T_PRD_WORK_PLAN T3 ON T3. ID = T1.WORK_PLAN_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON T3.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON T3.SHIPVOYAGE_ITEM_ID = TDSI. ID LEFT JOIN T_BUS_CARGO_INFO T4 ON T4. ID = T2.CARGO_INFO_ID LEFT JOIN T_PRD_WORK_TICKET_EQUIPMENT T5 ON T5.WORK_TICKET_DETAIL_ID = T2. ID LEFT JOIN T_BUS_TRUST T6 ON T3.TRUST_ID = T6.ID LEFT JOIN M_CARGO T7 ON T7.CARGO_CODE = T4.CARGO_CODE WHERE WORK_TICKET_STATUS IN ('10','20')
AND T3.WORK_DATE = #{workDate}
AND T3.CLASS_CODE = #{classCode}
AND T3.PLAN_TYPE = #{planType}
AND T7.WORK_TYPE = #{cargoType}
AND T3.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND T6.PORT_CODE = #{portCode}
