GROUP BY T1.ID, T3.TRUST_ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, T4.CARGO_OWNER_NAME, T4.CARGO_NAME, T4.CARGO_INFO_NO, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID, T2.DEPT_NAME, T5.EQUIPMENT_TYPE_NAME, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END, T2.TON, T2.QUANTITY, T2.CAR_COUNT, T2.END_TIME, T2.START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO ORDER BY T6.TRUST_NO

SELECT TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END shipvoyageLabel, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM STATUS_LABEL, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T6.CARGO_OWNER_NAME, T6.CARGO_OWNER_ID, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T5.TRUST_NO, T2.NUM AS LABOR_NUM, CASE WHEN TPWT.ID IS NULL THEN '待审核' ELSE TO_CHAR( TPWT.WORK_TICKET_STATUS_NAME ) END WORK_TICKET_STATUS_NAME, CASE WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) IS NULL THEN '待签票' WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) = '1' THEN '调度已签票' WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) = '2' THEN '库场已签票' ELSE '调度/库场已签票' END IS_SIGNED
FROM T_PRD_WORK_PLAN TPWP LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TPWP.SHIPVOYAGE_ID = TDS. ID LEFT JOIN M_SHIP MS ON TDS.SHIP_ID = MS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TPWP.SHIPVOYAGE_ITEM_ID = TDSI. ID JOIN M_CONSTANTS MC ON TPWP.STATUS = MC.CD AND MC.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN T_PRD_WORK_TICKET TPWT ON TPWP. ID = TPWT.WORK_PLAN_ID LEFT JOIN T_BUS_TRUST T5 ON TPWP.TRUST_ID = T5. ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_OWNER_NAME), ',' ) WITHIN GROUP (ORDER BY CARGO_OWNER_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME, TRUST_ID, REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_OWNER_ID), ',' ) WITHIN GROUP (ORDER BY CARGO_OWNER_ID), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T6 ON T5. ID = T6.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG (TO_CHAR(CARGO_NAME), ',') WITHIN GROUP (ORDER BY CARGO_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_NAME, REGEXP_REPLACE ( LISTAGG (TO_CHAR(CARGO_CODE), ',') WITHIN GROUP (ORDER BY CARGO_CODE), '([^,]+)(,\1)+', '\1' ) CARGO_CODE, TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T8 ON T5. ID = T8.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_AGENT_NAME), ',' ) WITHIN GROUP (ORDER BY CARGO_AGENT_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME, TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T7 ON T5. ID = T7.TRUST_ID LEFT JOIN T_PRD_DISPATCH T2 ON TPWP. ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' WHERE TPWP.STATUS != 10
AND T3.WORK_DATE >= TO_DATE (#{startDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND T3.WORK_DATE <= TO_DATE (#{endDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND TPWP.CLASS_CODE = #{classCode}
AND TPWP.PLAN_TYPE = #{planType}
AND T5.TRUST_NO = #{trustNo}
AND T5.PORT_CODE = #{portCode}
GROUP BY TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T6.CARGO_OWNER_NAME, T6.CARGO_OWNER_ID, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T5.TRUST_NO, T2.NUM, CASE WHEN TPWT.ID IS NULL THEN '待审核' ELSE TO_CHAR( TPWT.WORK_TICKET_STATUS_NAME ) END ORDER BY PLAN_NO

select TO_CHAR(REGEXP_REPLACE(LISTAGG(TO_CHAR(TDS2.SHIP_NAME ||'_'||TDSI2.VOYAGE), ',') WITHIN GROUP ( ORDER BY TDS2.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) "shipNameVoyage", TBCI2.ID "tbci2Id" from T_BUS_CARGO_INFO TBCI2 JOIN T_BUS_TRUST_CARGO TBTC2 ON TBCI2.ID = TBTC2.CARGO_INFO_ID JOIN T_BUS_TRUST TBT2 ON (TBT2.ID = TBTC2.TRUST_ID) JOIN T_DIS_SHIPVOYAGE_ITEM TDSI2 ON TBT2.SHIPVOYAGE_ITEM_ID = TDSI2.ID JOIN T_DIS_SHIPVOYAGE TDS2 ON TDS2.ID = TDSI2.SHIPVOYAGE_ID WHERE EXISTS ( select * from (
