        WORK_PLAN_ID = #{workPlanId, jdbcType=BIGINT}

select * from (
select TPWP.WORK_DATE,TPWP.CLASS_NAME,TPWP.CLASS_CODE, tmp_main.WORK_TICKET_ID,tmp_main.ALLOT_TYPE,tmp_main.PROCESS_DETAIL_CODE, MWP.PROCESS_NM PROCESS_DETAIL_NAME, tmp_tbci.CARGO_OWNER_NAME CARGO_OWNER_NAME, tmp_tbci.cargo_name CARGO_NAME, tmp_tbci.packing_name PACKING_NAME, tmp_tbci.packing_name PACKING_NAME_WAI_BAO, tmp_tbci.CARGO_INFO_NO, MWP2.IS_DIRECT_ACCESS, case when TBT.SHIPVOYAGE_ITEM_ID is null and TBT.type !='集港' then (select TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, to_char(TDS2.SHIP_NAME||'_'||TDSI2.VOYAGE) || ',') ORDER BY TDS2.SHIP_NAME) AS CLOB), ','), '([^,]+)(,\1)+', '\1'))
from T_BUS_TRUST_CARGO TBTC2 left join T_BUS_TRUST_CARGO TBTC3 on TBTC3.CARGO_INFO_ID = TBTC2.CARGO_INFO_ID left join T_BUS_TRUST TBT2 on TBTC3.TRUST_ID = TBT2.ID left join T_DIS_SHIPVOYAGE_ITEM TDSI2 on TDSI2.id = TBT2.SHIPVOYAGE_ITEM_ID left join T_DIS_SHIPVOYAGE TDS2 on TDSI2.SHIPVOYAGE_ID = TDS2.ID where TBTC2.TRUST_ID = TBT.ID and TBT2.TYPE in ('装船','卸船') group by TBTC2.TRUST_ID ) when TBT.SHIPVOYAGE_ITEM_ID is not null then to_char(TBT.SHIP_NAME||'_'||TBT.VOYAGE) end "shipvoyage", tmp_ticket.ton work_ton, (select TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, to_char(TDS2.scn) || ',') ORDER BY TDS2.SHIP_NAME) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) from T_BUS_TRUST_CARGO TBTC2 left join T_BUS_TRUST_CARGO TBTC3 on TBTC3.CARGO_INFO_ID = TBTC2.CARGO_INFO_ID left join T_BUS_TRUST TBT2 on TBTC3.TRUST_ID = TBT2.ID left join T_DIS_SHIPVOYAGE_ITEM TDSI2 on TDSI2.id = TBT2.SHIPVOYAGE_ITEM_ID left join T_DIS_SHIPVOYAGE TDS2 on TDSI2.SHIPVOYAGE_ID = TDS2.ID where TBTC2.TRUST_ID = TBT.ID and TBT2.TYPE in ('装船','卸船') group by TBTC2.TRUST_ID ) SCN, TPWP.process_name , TBT.TRUST_NO, TBT.TYPE trust_type, decode(TPWP.PLAN_TYPE,'1','船舶','2','集疏运','3','倒运',TPWP.PLAN_TYPE) plan_type from ( select TPWTD.WORK_TICKET_ID,ALLOT_TYPE,PROCESS_DETAIL_CODE from T_PRD_WORK_TICKET_DETAIL TPWTD where TPWTD.allot_type in ('2','3') group by TPWTD.WORK_TICKET_ID,ALLOT_TYPE,PROCESS_DETAIL_CODE ) tmp_main left join (select WORK_TICKET_ID, sum(ton) ton from T_PRD_WORK_TICKET_DETAIL where DEPT_NAME != '固机队' and ALLOT_TYPE ='1' group by WORK_TICKET_ID ) tmp_ticket on tmp_ticket.WORK_TICKET_ID = tmp_main.WORK_TICKET_ID
left join T_PRD_WORK_TICKET TPWT on TPWT.id = tmp_main.WORK_TICKET_ID left join T_PRD_WORK_PLAN TPWP on TPWP.id = TPWT.WORK_PLAN_ID left join (select TBTC.TRUST_ID trust_id, REGEXP_REPLACE( LISTAGG(TO_CHAR(TBCI.CARGO_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') cargo_name, REGEXP_REPLACE( LISTAGG(TO_CHAR(TBCI.CARGO_INFO_NO), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') CARGO_INFO_NO, REGEXP_REPLACE( LISTAGG(TO_CHAR(TBCI.PACKING_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') packing_name, REGEXP_REPLACE( LISTAGG(TO_CHAR(TBCI.CARGO_OWNER_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') CARGO_OWNER_NAME from T_BUS_TRUST_CARGO TBTC left join T_BUS_CARGO_INFO TBCI on TBTC.CARGO_INFO_ID = TBCI.ID group by TBTC.TRUST_ID ) tmp_tbci on tmp_tbci.trust_id = TPWP.TRUST_ID left join T_BUS_TRUST TBT on TBT.id = TPWP.TRUST_ID left join M_WORK_PROCESS MWP on MWP.PROCESS_CD = tmp_main.PROCESS_DETAIL_CODE left join M_WORK_PROCESS MWP2 on MWP2.PROCESS_CD = TPWP.PROCESS_CODE
where TPWP.work_date >= #{startTime,jdbcType=TIMESTAMP} and TPWP.work_date <=#{endTime,jdbcType=TIMESTAMP}
and tbt.trust_no like #{trustNoLike}
and tmp_tbci.packing_name like #{packingNameLike}
and tmp_tbci.cargo_name like #{cargoNameLike}
)
and "shipvoyage" like #{shipNameLike}
and "shipvoyage" like #{voyageLike}
and SCN like #{scnLike}
order by WORK_DATE asc, CLASS_CODE ASC,WORK_TICKET_ID ASC

select TPWT.ID from T_PRD_WORK_PLAN TPWP join T_PRD_WORK_TICKET TPWT on TPWP.id = TPWT.WORK_PLAN_ID where TPWP.PLAN_TYPE ='3' and EXISTS ( select * from (
select #{ticketId} as tmp_id from dual
) a where a.tmp_id = TPWT.ID ) group by TPWT.ID,TPWP.PLAN_TYPE

select * from (
select TPWP.WORK_DATE,TPWP.CLASS_CODE,TPWP.CLASS_NAME,TPWP.ID,TPWT.ID work_Ticket_Id,
TDS.SHIP_NAME||'_'||TDSI.VOYAGE "shipvoyage",
TDS.SCN,TPWP.PROCESS_NAME,TPWP.PROCESS_CODE,TPWTD.PROCESS_DETAIL_CODE,
TPWP.CARGO_NAME,
