    and TPWP.work_date <=#{endTime,jdbcType=TIMESTAMP}


        and TPWP.cargo_name like #{cargoNameLike}



        and TDS.SHIP_NAME like #{shipNameLike}



        and TDSI.VOYAGE like #{voyageLike}



        and SCN like #{scnLike}


group by TPWP.ID, TDS.SHIP_NAME,TDSI.VOYAGE,TDS.SCN, TPWP.PROCESS_NAME,
TPWP.PROCESS_CODE, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME,
TPWP.CARGO_NAME,TPWT.ID,TPWTD.PROCESS_DETAIL_CODE
              )


        and trust_no = #{trustNo}


