select sum(WEIGHT_GOODS)
from WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND
where PLAN_NO in (select BUSINESS_NO
                  from T_BUS_TRUST_CARGO where TRUST_ID = #{trustId}
)
  and WEIGH_IN_DT >= #{startTime,jdbcType=TIMESTAMP} and WEIGH_IN_DT < #{endTime,jdbcType=TIMESTAMP}

select * from ( select TPWP.WORK_DATE, decode (TPWTD.EXTERNAL_STATUS,'10','待审核','20','生产已审核','30','Hr已审核',TPWTD.EXTERNAL_STATUS) status, TPWTD.EXTERNAL_STATUS, TPWTD.id ticket_detail_id, TPWP.CLASS_NAME, TPWP.CLASS_CODE, TPWTD.WORK_TICKET_ID, TPWTD.ALLOT_TYPE, TPWTD.PROCESS_DETAIL_CODE, MWP.PROCESS_NM PROCESS_DETAIL_NAME, tmp_tbci.CARGO_OWNER_NAME CARGO_OWNER_NAME, tmp_tbci.cargo_name CARGO_NAME, tmp_tbci.packing_name PACKING_NAME, nvl(tmp_tbci.PACKING_NAME_WAI_BAO ,TPWTD.WB_PACKING_NAME) PACKING_NAME_WAI_BAO, tmp_tbci.CARGO_INFO_NO, MWP.IS_DIRECT_ACCESS, tpwtd.DEPT_ID, case when MWP2.IS_DIRECT_ACCESS ='1' or TPWP.PROCESS_NAME = '车/岸(前沿直取)' then '01' when tbt.TYPE='疏港' or TPWP.PROCESS_NAME= '车/场(集港)' or TPWP.PROCESS_NAME= '场/车(疏港)' or TPWTD.PROCESS_DETAIL_NAME = '场-车(疏港)' then '02' else tpwtd.WORK_POSITION_CODE end WORK_POSITION_CODE, case when MWP2.IS_DIRECT_ACCESS ='1' or TPWP.PROCESS_NAME = '车/岸(前沿直取)' then '前沿' when tbt.TYPE='疏港' or TPWP.PROCESS_NAME= '车/场(集港)' or TPWP.PROCESS_NAME= '场/车(疏港)' or TPWTD.PROCESS_DETAIL_NAME = '场-车(疏港)' then '后场' else tpwtd.WORK_POSITION_NAME end WORK_POSITION_NAME, sd.DEPT_NAME "deptName",sd.parent_id, tpwtd.ton work_ton, tpwtd.PRICE "price", tpwtd.AMOUNT "amount", tmp_ticket.ton "ticketTon", case when TBT.SHIPVOYAGE_ITEM_ID is null and TBT.type != '集港' then (select TO_CHAR(REGEXP_REPLACE(RTRIM( XMLCAST(XMLAGG( XMLELEMENT(E, to_char(TDS2.SHIP_NAME || '_' || TDSI2.VOYAGE) || ',') ORDER BY TDS2.SHIP_NAME) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) from T_BUS_TRUST_CARGO TBTC2 left join T_BUS_TRUST_CARGO TBTC3 on TBTC3.CARGO_INFO_ID = TBTC2.CARGO_INFO_ID left join T_BUS_TRUST TBT2 on TBTC3.TRUST_ID = TBT2.ID left join T_DIS_SHIPVOYAGE_ITEM TDSI2 on TDSI2.id = TBT2.SHIPVOYAGE_ITEM_ID left join T_DIS_SHIPVOYAGE TDS2 on TDSI2.SHIPVOYAGE_ID = TDS2.ID where TBTC2.TRUST_ID = TBT.ID and TBT2.TYPE in ('装船', '卸船') group by TBTC2.TRUST_ID) when TBT.SHIPVOYAGE_ITEM_ID is not null then to_char(TBT.SHIP_NAME || '_' || TBT.VOYAGE) end "shipvoyage", case when TBT.SHIPVOYAGE_ITEM_ID is null and TBT.type != '集港' then to_char((select TO_CHAR(REGEXP_REPLACE( RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, to_char(TDS2.scn) || ',') ORDER BY TDS2.SHIP_NAME) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) from T_BUS_TRUST_CARGO TBTC2 left join T_BUS_TRUST_CARGO TBTC3 on TBTC3.CARGO_INFO_ID = TBTC2.CARGO_INFO_ID left join T_BUS_TRUST TBT2 on TBTC3.TRUST_ID = TBT2.ID left join T_DIS_SHIPVOYAGE_ITEM TDSI2 on TDSI2.id = TBT2.SHIPVOYAGE_ITEM_ID left join T_DIS_SHIPVOYAGE TDS2 on TDSI2.SHIPVOYAGE_ID = TDS2.ID where TBTC2.TRUST_ID = TBT.ID and TBT2.TYPE in ('装船', '卸船') group by TBTC2.TRUST_ID)) when TBT.SHIPVOYAGE_ITEM_ID is not null then to_char(tds.scn) end SCN, TPWP.process_name, TPWP.process_Code, TBT.TRUST_NO, TBT.TYPE trust_type, decode(TPWP.PLAN_TYPE, '1', '船舶', '2', '集疏运', '3', '倒运', TPWP.PLAN_TYPE) plan_type, tmp_equ."equipmentTypeName" "equipmentTypeName" from T_PRD_WORK_PLAN TPWP left join T_PRD_WORK_TICKET TPWT on TPWP.id = TPWT.WORK_PLAN_ID left join T_PRD_WORK_TICKET_DETAIL TPWTD on TPWT.id = TPWTD.WORK_TICKET_ID left join (select WORK_TICKET_ID, sum(ton) ton from T_PRD_WORK_TICKET_DETAIL where DEPT_NAME != '固机队' and ALLOT_TYPE ='1' group by WORK_TICKET_ID ) tmp_ticket on tmp_ticket.WORK_TICKET_ID = TPWTD.WORK_TICKET_ID left join (select TBTC.TRUST_ID trust_id, REGEXP_REPLACE(LISTAGG(TO_CHAR(TBCI.CARGO_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') cargo_name, REGEXP_REPLACE(LISTAGG(TO_CHAR(TBCI.CARGO_INFO_NO), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') CARGO_INFO_NO, REGEXP_REPLACE(LISTAGG(TO_CHAR(TBCI.PACKING_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') packing_name, REGEXP_REPLACE(LISTAGG(TO_CHAR(TBCI.CARGO_OWNER_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') CARGO_OWNER_NAME, REGEXP_REPLACE(LISTAGG(TO_CHAR(mc.OUTWARD_TYPE_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') PACKING_NAME_WAI_BAO from T_BUS_TRUST_CARGO TBTC left join T_BUS_CARGO_INFO TBCI on TBTC.CARGO_INFO_ID = TBCI.ID left join M_cargo mc on mc.cargo_code = tbci.cargo_code group by TBTC.TRUST_ID) tmp_tbci on tmp_tbci.trust_id = TPWP.TRUST_ID left join T_BUS_TRUST TBT on TBT.id = TPWP.TRUST_ID left join t_dis_shipvoyage_item tdsi on tdsi.id = tbt.SHIPVOYAGE_ITEM_ID left join t_dis_shipvoyage tds on tds.id = tdsi.SHIPVOYAGE_ID left join M_WORK_PROCESS MWP on MWP.PROCESS_CD = TPWTD.PROCESS_DETAIL_CODE left join M_WORK_PROCESS MWP2 on MWP2.PROCESS_CD = TPWP.PROCESS_CODE left join sys_dept sd on sd.id = tpwtd.dept_id left join (select WORK_TICKET_DETAIL_ID, REGEXP_REPLACE(LISTAGG(TO_CHAR(EQUIPMENT_TYPE_NAME), ',') WITHIN GROUP ( ORDER BY EQUIPMENT_TYPE_NAME ),'([^,]+)(,\1)+', '\1') "equipmentTypeName" from T_PRD_WORK_TICKET_EQUIPMENT group by WORK_TICKET_DETAIL_ID) tmp_equ on tmp_equ.WORK_TICKET_DETAIL_ID = TPWTD.ID where TPWTD.ALLOT_TYPE in('2','3') and sd.dept_name !='流机队'
