SELECT MAX(tpds.ID) "id", tbt.ID "trustId", tdsi.ID "shipVoyageItemId", tbt.PORT_NAME "portName", tbt.TRUST_NO "trustNo", tds.scn "scn", tds.SHIP_NAME || '_' || tdsi.VOYAGE "shipVoyageName", tbtc.packing_name "packingName", tdsi.TRADE_TYPE "tradeType", TBTC.CARGO_CODE "cargoCode", TBTC.CARGO_NAME "cargoName", mc.OUTWARD_TYPE "outwardType", mc.OUTWARD_TYPE_NAME "outwardTypeName", sd.ID "deptId", sd.DEPT_NAME "deptName", MAX(tpds.KC_STATUS) "kcStatus", MAX(tpds.DD_STATUS) "ddStatus", MAX(tpds.WF_STATUS) "wfStatus", MAX(tpds.HR_STATUS) "hrStatus", sum(wrp.WEIGHT_GOODS) "ton" FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND wrp LEFT JOIN T_BUS_VEHICLE_TRANSFER tbvt ON TO_CHAR(TBVT.id) = WRP.TSPT_ID LEFT JOIN T_BUS_TRUST tbt ON TBVT.TRUST_ID = Tbt.ID LEFT JOIN T_BUS_TRUST_CARGO tbtc ON tbt.id = TBTC.TRUST_ID LEFT JOIN M_CARGO mc ON TBTC.CARGO_CODE = mc.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE_ITEM tdsi ON TDSI.id = tbt.SHIPVOYAGE_ITEM_ID LEFT JOIN T_DIS_SHIPVOYAGE tds ON TDS.id = tdsi.SHIPVOYAGE_ID LEFT JOIN M_MACHINE mm ON tbvt.EQUIPMENT_ID = mm.id LEFT JOIN SYS_DEPT sd ON sd.id = mm.DEPT_ID LEFT JOIN T_PRD_DY_SUM tpds ON TPDS.TRUST_ID = TBT.ID AND TPDS.DEPT_ID = sd.id AND tpds.PORT_NAME = TBT.PORT_NAME AND tpds.OUTWARD_TYPE = MC.OUTWARD_TYPE AND tpds.packing_name = tbtc.packing_name AND tpds.CARGO_CODE = tbtc.CARGO_CODE WHERE TBVT.DEL_FLAG = '0' AND wrp.WEIGHT_GOODS !=0
AND wrp.WEIGH_OUT_DT >= #{startDate}
AND wrp.WEIGH_OUT_DT <= #{endDate}
AND tds.SHIP_NAME = #{shipName}
AND sd.DEPT_NAME = #{deptName}
AND sd.ID = #{deptId}
HAVING sum(wrp.WEIGHT_GOODS) >0 GROUP BY tbt.PORT_NAME, tbt.ID, tbt.TRUST_NO, tds.scn, tds.SHIP_NAME, tdsi.VOYAGE, tbtc.packing_name, tdsi.TRADE_TYPE , TBTC.CARGO_NAME , mc.OUTWARD_TYPE , mc.OUTWARD_TYPE_NAME , sd.DEPT_NAME, tdsi.ID, TBTC.CARGO_CODE, sd.ID

