update T_PRD_WORK_TICKET_DETAIL
set EXTERNAL_STATUS = #{status},
    EXTERNAL_PRD_BY= #{userBy,jdbcType=BIGINT},
    EXTERNAL_PRD_BY_NAME=#{userByName,jdbcType=VARCHAR},
    EXTERNAL_PRD_TIME = #{userTime,jdbcType=TIMESTAMP}
    where WORK_DATE >=#{startTime,jdbcType=TIMESTAMP}
              and work_date <= #{endTime,jdbcType=TIMESTAMP}

        and DEPT_ID  = #{deptId,jdbcType=BIGINT}

update T_PRD_WORK_TICKET_DETAIL
set EXTERNAL_STATUS = #{status},
    EXTERNAL_PRD_BY= #{userBy,jdbcType=BIGINT},
    EXTERNAL_PRD_BY_NAME=#{userByName,jdbcType=VARCHAR},
    EXTERNAL_PRD_TIME = #{userTime,jdbcType=TIMESTAMP}
    where to_date(to_char(work_date,'yyyy-MM'),'yyyy-MM') = #{startTime,jdbcType=TIMESTAMP}

        and DEPT_ID  = #{deptId,jdbcType=BIGINT}

update T_PRD_WORK_TICKET_DETAIL
set EXTERNAL_STATUS = #{status},
    EXTERNAL_PRD_BY= #{userBy,jdbcType=BIGINT},
    EXTERNAL_PRD_BY_NAME=#{userByName,jdbcType=VARCHAR},
    EXTERNAL_PRD_TIME = #{userTime,jdbcType=TIMESTAMP}
    where id in (
        select distinct TPWTD.id
        from T_PRD_WORK_TICKET_DETAIL TPWTD
        left join T_PRD_WORK_TICKET TPWT on TPWTD.WORK_TICKET_ID = TPWT.ID
        left join T_PRD_WORK_PLAN TPWP on TPWT.WORK_PLAN_ID = TPWP.ID
        where TPWP.PLAN_TYPE = '4' and TPWP.WORK_DATE >=#{startTime,jdbcType=TIMESTAMP}
        and TPWP.work_date <= #{endTime,jdbcType=TIMESTAMP}
        )

        and DEPT_ID  = #{deptId,jdbcType=BIGINT}

UPDATE T_PRD_WORK_TICKET_DETAIL
set EXTERNAL_STATUS = #{status},
EXTERNAL_HR_BY= #{userBy2,jdbcType=BIGINT},
EXTERNAL_HR_BY_NAME=#{userByName2,jdbcType=VARCHAR},
EXTERNAL_HR_TIME = #{userTime2,jdbcType=TIMESTAMP}
where to_date(to_char(work_date,'yyyy-MM'),'yyyy-MM') = #{startTime,jdbcType=TIMESTAMP}

        and DEPT_ID  = #{deptId,jdbcType=BIGINT}

UPDATE T_PRD_WF_SETTLEMENT
SET DD_STATUS = #{ddStatus},
KC_STATUS = #{kcStatus},
LZ_STATUS = #{lzStatus},
WF_STATUS = #{wfStatus}
