AND SETTLEMENT_DATE <= #{endDate}

    AND DISTRIBUTE_TYPE = #{distributeType}

UPDATE T_PRD_WF_SETTLEMENT
SET DD_STATUS = #{ddStatus},
KC_STATUS = #{kcStatus},
LZ_STATUS = #{lzStatus},
WF_STATUS = #{wfStatus}
WHERE SETTLEMENT_DATE >= #{startDate}
AND SETTLEMENT_DATE <= #{endDate}

    AND DISTRIBUTE_TYPE = #{distributeType}

UPDATE T_PRD_WF_SETTLEMENT
SET DD_STATUS = #{status},
    d_status_by = #{userId},
    d_status_by_name = #{userName},
    d_status_time = #{nowDate,jdbcType=TIMESTAMP}
WHERE to_char(SETTLEMENT_DATE,'yyyy-MM') = #{startDate,jdbcType=VARCHAR}

    AND DISTRIBUTE_TYPE = #{distributeType}

UPDATE T_PRD_WF_SETTLEMENT
