SELECT a.DEPT_NAME "deptName", a.OUTWARD_TYPE_NAME "outwardTypeName", a.PROCESS_NAME "processName", a.PROCESS_DETAIL_NAME "processDetailName", a.WORK_POSITION_NAME "workPositionName", a.DISTRIBUTE_TYPE_NAME "distributeTypeName", a.WORK_TON "workTon", b.WEIGHT_TON "weightTon", a.REMARK "remark", CASE WHEN b.DD_STATUS IS NULL THEN a.DD_STATUS WHEN a.DD_STATUS < b.DD_STATUS THEN a.DD_STATUS ELSE b.DD_STATUS END "ddStatus", CASE WHEN b.KC_STATUS IS NULL THEN a.KC_STATUS WHEN a.KC_STATUS < b.KC_STATUS THEN a.KC_STATUS ELSE b.KC_STATUS END "kcStatus", CASE WHEN b.LZ_STATUS IS NULL THEN a.LZ_STATUS WHEN a.LZ_STATUS < b.LZ_STATUS THEN a.LZ_STATUS ELSE b.LZ_STATUS END "lzStatus", CASE WHEN b.WF_STATUS IS NULL THEN a.WF_STATUS WHEN a.WF_STATUS < b.WF_STATUS THEN a.WF_STATUS ELSE b.WF_STATUS END "wfStatus" FROM ( SELECT DEPT_ID, DEPT_NAME, OUTWARD_TYPE_CODE, MAX(OUTWARD_TYPE_NAME) OUTWARD_TYPE_NAME, PROCESS_CODE , MAX(PROCESS_NAME) PROCESS_NAME, WORK_POSITION_CODE, WORK_POSITION_NAME , PROCESS_DETAIL_CODE, CASE WHEN DISTRIBUTE_TYPE = '2' THEN '机械分配' WHEN DISTRIBUTE_TYPE = '3' THEN '人员分配' END DISTRIBUTE_TYPE_NAME, MAX(PROCESS_DETAIL_NAME) PROCESS_DETAIL_NAME, SUM(WORK_TON) WORK_TON, CASE WHEN MECHANICAL_TYPE = 1 THEN '行吊' END REMARK, MIN(DD_STATUS) DD_STATUS, MIN(KC_STATUS) KC_STATUS, MIN(LZ_STATUS) LZ_STATUS, MIN(WF_STATUS) WF_STATUS FROM T_PRD_WF_SETTLEMENT tpws WHERE IS_DAOYUN = 0
and DEPT_NAME LIKE #{deptNameLike}
AND SETTLEMENT_DATE >= TO_DATE(#{startDate},'YYYY-MM-DD hh24:mi:ss')
AND SETTLEMENT_DATE < TO_DATE(#{endDate},'YYYY-MM-DD hh24:mi:ss')
AND DISTRIBUTE_TYPE = #{distributeType}
#{item,jdbcType=VARCHAR}
GROUP BY DEPT_ID, DEPT_NAME, TPWS.OUTWARD_TYPE_CODE, PROCESS_CODE , WORK_POSITION_NAME , WORK_POSITION_CODE, DISTRIBUTE_TYPE, PROCESS_DETAIL_CODE, MECHANICAL_TYPE ) a LEFT JOIN ( SELECT DEPT_ID, DEPT_NAME, OUTWARD_TYPE_CODE, MAX(OUTWARD_TYPE_NAME), PROCESS_CODE , MAX(PROCESS_NAME) , WORK_POSITION_CODE, WORK_POSITION_NAME , PROCESS_DETAIL_CODE, MAX(PROCESS_DETAIL_NAME), SUM(WORK_TON), SUM(WEIGHT_TON) WEIGHT_TON, MIN(DD_STATUS) DD_STATUS, MIN(KC_STATUS) KC_STATUS, MIN(LZ_STATUS) LZ_STATUS, MIN(WF_STATUS) WF_STATUS FROM T_PRD_WF_SETTLEMENT tpws WHERE IS_DAOYUN = 1
and DEPT_NAME LIKE #{deptNameLike}
AND SETTLEMENT_DATE >= TO_DATE(#{startDate},'YYYY-MM-DD hh24:mi:ss')
AND SETTLEMENT_DATE < TO_DATE(#{endDate},'YYYY-MM-DD hh24:mi:ss')
AND DISTRIBUTE_TYPE = #{distributeType}
#{item,jdbcType=VARCHAR}
GROUP BY DEPT_ID, DEPT_NAME, OUTWARD_TYPE_CODE, PROCESS_CODE , WORK_POSITION_NAME , WORK_POSITION_CODE, PROCESS_DETAIL_CODE ORDER BY OUTWARD_TYPE_CODE ,PROCESS_CODE ,WORK_POSITION_CODE ,PROCESS_DETAIL_CODE ) b ON a.OUTWARD_TYPE_CODE = b.OUTWARD_TYPE_CODE AND a.WORK_POSITION_CODE = b.WORK_POSITION_CODE AND a.DEPT_ID = b.DEPT_ID ORDER BY a.OUTWARD_TYPE_CODE ,a.DEPT_NAME,a.WORK_POSITION_NAME,a.PROCESS_CODE ,a.WORK_POSITION_CODE ,a.PROCESS_DETAIL_CODE

SELECT LISTAGG(tpws.id, ',') WITHIN GROUP (ORDER BY tpws.id) AS "ids", DEPT_ID "deptId", DEPT_NAME "deptName", OUTWARD_TYPE_CODE "outwardTypeCode", MAX(OUTWARD_TYPE_NAME) "outwardTypeName", PROCESS_CODE "processCode", MAX(PROCESS_NAME) "processName", WORK_POSITION_CODE "workPositionCode", WORK_POSITION_NAME "workPositionName", PROCESS_DETAIL_CODE "processDetailCode", MAX(PROCESS_DETAIL_NAME) "processDetailName", SUM(WORK_TON) "workTon", SUM(WEIGHT_TON) "weightTon", MIN(DD_STATUS) "ddStatus", MIN(KC_STATUS) "kcStatus", MIN(LZ_STATUS) "lzStatus", MIN(WF_STATUS) "wfStatus", MIN(D_STATUS_BY_NAME) "dStatusByName", MIN(K_STATUS_BY_NAME) "kStatusByName", MIN(W_STATUS_BY_NAME) "wStatusByName", MIN(L_STATUS_BY_NAME) "lStatusByName" FROM T_PRD_WF_SETTLEMENT tpws WHERE IS_DAOYUN = 1
and DEPT_NAME LIKE #{deptNameLike}
AND SETTLEMENT_DATE >= TO_DATE(#{startDate},'YYYY-MM-DD hh24:mi:ss')
AND SETTLEMENT_DATE < TO_DATE(#{endDate},'YYYY-MM-DD hh24:mi:ss')
AND DISTRIBUTE_TYPE = #{distributeType}
#{item,jdbcType=VARCHAR}
GROUP BY DEPT_ID, DEPT_NAME, OUTWARD_TYPE_CODE, PROCESS_CODE , WORK_POSITION_NAME , WORK_POSITION_CODE, PROCESS_DETAIL_CODE ORDER BY OUTWARD_TYPE_CODE ,DEPT_NAME,WORK_POSITION_CODE

SELECT LISTAGG(tpws.id, ',') WITHIN GROUP (ORDER BY tpws.id) AS "ids", tpws.DEPT_ID "deptId", sd2.ID "mainDeptId", tpws.DEPT_NAME "deptName", OUTWARD_TYPE_CODE "outwardTypeCode", MAX(OUTWARD_TYPE_NAME) "outwardTypeName", PROCESS_CODE "processCode", MAX(PROCESS_NAME) "processName", WORK_POSITION_CODE "workPositionCode", WORK_POSITION_NAME "workPositionName", PROCESS_DETAIL_CODE "processDetailCode", CASE WHEN DISTRIBUTE_TYPE = '2' THEN '机械分配' WHEN DISTRIBUTE_TYPE = '3' THEN '人员分配' END "distributeTypeName" , MAX(PROCESS_DETAIL_NAME) "processDetailName", SUM(WORK_TON) "workTon", CASE WHEN MECHANICAL_TYPE = 1 THEN '行吊' END "remark", MIN(DD_STATUS) "ddStatus", MIN(KC_STATUS) "kcStatus", MIN(LZ_STATUS) "lzStatus", MIN(WF_STATUS) "wfStatus", MIN(D_STATUS_BY_NAME) "dStatusByName", MIN(K_STATUS_BY_NAME) "kStatusByName", MIN(W_STATUS_BY_NAME) "wStatusByName", MIN(L_STATUS_BY_NAME) "lStatusByName" FROM T_PRD_WF_SETTLEMENT tpws left join SYS_DEPT sd1 on sd1.ID = tpws.DEPT_ID left join SYS_DEPT sd2 on sd2.ID = sd1.PARENT_ID WHERE IS_DAOYUN = 0
and tpws.DEPT_NAME LIKE #{deptNameLike}
AND SETTLEMENT_DATE >= TO_DATE(#{startDate},'YYYY-MM-DD hh24:mi:ss')
AND SETTLEMENT_DATE < TO_DATE(#{endDate},'YYYY-MM-DD hh24:mi:ss')
AND DISTRIBUTE_TYPE = #{distributeType}
AND sd2.ID = #{mainDeptId}
#{item,jdbcType=VARCHAR}
GROUP BY tpws.DEPT_ID, sd2.ID, tpws.DEPT_NAME, OUTWARD_TYPE_CODE, PROCESS_CODE , WORK_POSITION_NAME , WORK_POSITION_CODE, DISTRIBUTE_TYPE, PROCESS_DETAIL_CODE, MECHANICAL_TYPE ORDER BY OUTWARD_TYPE_CODE ,tpws.DEPT_NAME,WORK_POSITION_CODE,WORK_POSITION_NAME,PROCESS_CODE ,PROCESS_DETAIL_CODE

mapper.insert:
INSERT INTO T_PRD_WF_SETTLEMENT (ID, SETTLEMENT_DATE, DISTRIBUTE_TYPE, DEPT_ID, DEPT_NAME, OUTWARD_TYPE_CODE, OUTWARD_TYPE_NAME, PROCESS_CODE, PROCESS_NAME, PROCESS_DETAIL_CODE, PROCESS_DETAIL_NAME, WORK_POSITION_CODE, WORK_POSITION_NAME, MECHANICAL_TYPE, WORK_TON,WEIGHT_TON, DD_STATUS,KC_STATUS,LZ_STATUS,WF_STATUS, CREATE_BY, CREATE_BY_NAME, CREATE_TIME,IS_DAOYUN) (
